const tg = $('Telegram Trigger').item.json.message;
const chatId = String(tg.from.id);
const texto = (tg.text || '').trim();

const user = $('Guardar Usuario').item.json || {};
const activoTexto = String(user.activo || '').trim().toUpperCase();
const activo = ['TRUE', 'VERDADERO', 'SI', 'SÍ', '1', 'ACTIVO'].includes(activoTexto);

const sesiones = $('Leer sesiones').all().map(i => i.json);
const solicitudes = $('Leer solicitudes').all().map(i => i.json).filter(s => s.id_ticket);

const ticketsPorId = new Map();

for (const s of solicitudes) {
  const id = String(s.id_ticket || '').trim();
  if (id) {
    ticketsPorId.set(id, s);
  }
}

const solicitudesUnicas = Array.from(ticketsPorId.values());

const misSesiones = sesiones
  .filter(s => String(s.telegram_user).trim() === chatId)
  .sort((a, b) => new Date(b.updated_at || 0) - new Date(a.updated_at || 0));

const sesion = misSesiones[0] || {};
let pantalla = sesion.pantalla_actual || 'menu';

let datos = {};
try {
  datos = JSON.parse(sesion.datos_temp || '{}');
} catch (e) {
  datos = {};
}

const menu = `Hola, soy HelpDeskBot 👋

Estoy aquí para ayudarte con solicitudes de soporte
de forma rápida y ordenada.

Por favor escribe el número de la opción que quieras usar.

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;

if (!activo) {
  return [{
    json: {
      chat_id: chatId,
      respuesta: '❌ No tienes acceso al sistema. Contacta al administrador.',
      pantalla_actual: 'menu',
      datos_temp: '{}',
      guardar_ticket: false,
      actualizar_estado: false,
      ticket_estado: null,
      log_resultado: 'usuario_inactivo',
      opcion: texto
    }
  }];
}

let respuesta = '';
let guardarTicket = false;
let ticket = null;

if (texto === '/start') {
  pantalla = 'menu';
  respuesta = menu;
  datos = {};
} else if (pantalla === 'menu') {
  if (texto === '0') {
    respuesta = `Ayuda de HelpDeskBot

Puedes usar estas opciones:

1. Crear solicitud
Registra una nueva solicitud de soporte paso a paso.

2. Consultar estado de solicitud
Permite escribir el ID de un ticket para ver su estado actual.

3. Mis solicitudes
Muestra tus solicitudes registradas.

4. Reportes
Muestra un resumen general de solicitudes por estado y prioridad.

5. Configuración
Muestra tu información de usuario. Si eres administrador, permite cambiar estados de tickets.

9. Cancelar
Durante la creación o edición de una solicitud, cancela el proceso actual.

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
  } else if (texto === '1') {
    pantalla = 'tipo';
    respuesta = `Vamos a crear una solicitud, para lo cual se necesitará escoger su tipo.

Selecciona el tipo:
1. Soporte técnico
2. Solicitud administrativa
3. Consulta general
9. Cancelar`;
  } else if (texto === '2') {
    pantalla = 'consultar';
    respuesta = 'Escribe el ID del ticket que quieres consultar.\n\n9. Cancelar';
  } else if (texto === '3') {
    const misTickets = solicitudesUnicas
      .filter(s => String(s.creado_por).trim() === chatId)
      .slice(-5)
      .reverse();

    if (misTickets.length === 0) {
      respuesta = `No tienes solicitudes registradas todavía.

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
    } else {
      const lista = misTickets.map(t => {
        return `ID: ${t.id_ticket}
Tipo: ${t.tipo}
Prioridad: ${t.prioridad}
Estado: ${t.estado}`;
      }).join('\n\n');

      respuesta = `Tus últimas solicitudes:

${lista}

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
    }
  } else if (texto === '4') {
    const total = solicitudesUnicas.length;
    const abiertos = solicitudesUnicas.filter(s => String(s.estado || '').toLowerCase() === 'abierto').length;
    const enProceso = solicitudesUnicas.filter(s => String(s.estado || '').toLowerCase() === 'en proceso').length;
    const cerrados = solicitudesUnicas.filter(s => String(s.estado || '').toLowerCase() === 'cerrado').length;
    const alta = solicitudesUnicas.filter(s => String(s.prioridad || '').toLowerCase() === 'alta').length;
    const media = solicitudesUnicas.filter(s => String(s.prioridad || '').toLowerCase() === 'media').length;
    const baja = solicitudesUnicas.filter(s => String(s.prioridad || '').toLowerCase() === 'baja').length;

    respuesta = `Reporte general de solicitudes:

Total: ${total}
Abiertas: ${abiertos}
En proceso: ${enProceso}
Cerradas: ${cerrados}

Por prioridad:
Alta: ${alta}
Media: ${media}
Baja: ${baja}

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
  } else if (texto === '5') {
    const esAdmin = String(user.rol || '').trim().toLowerCase() === 'admin';

    if (esAdmin) {
      pantalla = 'admin_config';
      respuesta = `Configuración / Administración:

1. Cambiar estado de solicitud
9. Volver al menú`;
    } else {
      respuesta = `Configuración de usuario:

Usuario Telegram: ${chatId}
Nombre: ${user.nombre || 'No registrado'}
Rol: ${user.rol || 'usuario'}
Activo: ${activo ? 'Sí' : 'No'}

El bot opera con menú numérico y registra solicitudes en Google Sheets.

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
    }
  } else {
    respuesta = menu;
  }
} else if (pantalla === 'admin_config') {
  if (texto === '1') {
    pantalla = 'estado_id';
    respuesta = 'Escribe el ID del ticket cuyo estado quieres cambiar.\n\n9. Cancelar';
  } else if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else {
    respuesta = 'Opción no válida.\n\n1. Cambiar estado de solicitud\n9. Volver al menú';
  }
} else if (pantalla === 'estado_id') {
  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else {
    datos.id_ticket_estado = texto;
    pantalla = 'estado_nuevo';
    respuesta = 'Selecciona el nuevo estado:\n\n1. Abierto\n2. En proceso\n3. Cerrado\n9. Cancelar';
  }
} else if (pantalla === 'estado_nuevo') {
  const estados = {
    '1': 'Abierto',
    '2': 'En proceso',
    '3': 'Cerrado'
  };

  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else if (!estados[texto]) {
    respuesta = 'Estado no válido.\n\n1. Abierto\n2. En proceso\n3. Cerrado\n9. Cancelar';
  } else {
    const nuevoEstado = estados[texto];
    ticket = {
      id_ticket: datos.id_ticket_estado,
      estado: nuevoEstado
    };
    guardarTicket = true;
    pantalla = 'menu';
    datos = {};
    respuesta = `✅ El estado del ticket ${ticket.id_ticket} será actualizado a: ${nuevoEstado}`;
  }
} else if (pantalla === 'tipo') {
  const tipos = {
    '1': 'Soporte técnico',
    '2': 'Solicitud administrativa',
    '3': 'Consulta general'
  };

  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else if (!tipos[texto]) {
    respuesta = '⚠️ Opción no válida.\n1. Soporte técnico\n2. Solicitud administrativa\n3. Consulta general\n9. Cancelar';
  } else {
    datos.tipo = tipos[texto];
    pantalla = 'prioridad';
    respuesta = 'Selecciona la prioridad:\n1. Alta\n2. Media\n3. Baja\n9. Cancelar';
  }
} else if (pantalla === 'prioridad') {
  const prioridades = {
    '1': 'Alta',
    '2': 'Media',
    '3': 'Baja'
  };

  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else if (!prioridades[texto]) {
    respuesta = '⚠️ Prioridad no válida.\n1. Alta\n2. Media\n3. Baja\n9. Cancelar';
  } else {
    datos.prioridad = prioridades[texto];
    pantalla = 'descripcion';
    respuesta = 'Describe la solicitud con mínimo 10 caracteres.\n\n9. Cancelar';
  }
} else if (pantalla === 'descripcion') {
  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else if (texto.length < 10) {
    respuesta = '⚠️ La descripción es muy corta. Escribe mínimo 10 caracteres.';
  } else {
    datos.descripcion = texto;
    pantalla = 'confirmacion';
    respuesta = `Resumen de tu solicitud:

Tipo: ${datos.tipo}
Prioridad: ${datos.prioridad}
Descripción: ${datos.descripcion}

¿Confirmas?
1. Sí, guardar
2. Editar descripción
9. Cancelar`;
  }
} else if (pantalla === 'confirmacion') {
  if (texto === '1') {
    const idTicket = `HD-${Date.now()}`;
    ticket = {
      id_ticket: idTicket,
      tipo: datos.tipo,
      prioridad: datos.prioridad,
      descripcion: datos.descripcion,
      estado: 'Abierto',
      creado_por: chatId,
      fecha_creacion: new Date().toISOString()
    };

    guardarTicket = true;
    pantalla = 'menu';
    datos = {};
    respuesta = `✅ Solicitud creada exitosamente.

ID: ${idTicket}
Estado: Abierto

Puedes consultar el estado más adelante.`;
  } else if (texto === '2') {
    pantalla = 'descripcion';
    respuesta = 'Vuelve a escribir la descripción.';
  } else if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else {
    respuesta = '⚠️ Opción no válida.\n1. Sí, guardar\n2. Editar descripción\n9. Cancelar';
  }
} else if (pantalla === 'consultar') {
  if (texto === '9') {
    pantalla = 'menu';
    datos = {};
    respuesta = menu;
  } else {
    const ticketEncontrado = solicitudesUnicas.find(s =>
      String(s.id_ticket || '').trim() === texto
    );

    pantalla = 'menu';
    datos = {};

    if (!ticketEncontrado) {
      respuesta = `No encontré una solicitud con ese ID.

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
    } else {
      respuesta = `Estado de solicitud:

ID: ${ticketEncontrado.id_ticket}
Tipo: ${ticketEncontrado.tipo}
Prioridad: ${ticketEncontrado.prioridad}
Descripción: ${ticketEncontrado.descripcion}
Estado: ${ticketEncontrado.estado}
Fecha creación: ${ticketEncontrado.fecha_creacion}

Menú principal:
0. Ayuda
1. Crear solicitud
2. Consultar estado de solicitud
3. Mis solicitudes
4. Reportes
5. Configuración`;
    }
  }
} else {
  pantalla = 'menu';
  respuesta = menu;
  datos = {};
}

const actualizarEstado = guardarTicket && ticket && !ticket.tipo;
const ticketEstado = actualizarEstado ? ticket : null;

return [{
  json: {
    chat_id: chatId,
    respuesta,
    pantalla_actual: pantalla,
    datos_temp: JSON.stringify(datos),
    guardar_ticket: guardarTicket && !actualizarEstado,
    ticket: actualizarEstado ? null : ticket,
    actualizar_estado: actualizarEstado,
    ticket_estado: ticketEstado,
    opcion: texto,
    log_resultado: guardarTicket ? (actualizarEstado ? 'estado_actualizado' : 'ticket_creado') : 'mensaje_procesado'
  }
}];
